class User:
    _users = []
    _next_id = 1

    def __init__(self, name, email, age):
        if not User.validate_email(email):
            raise ValueError(f"Invalid email: {email}")
        if not User.validate_age(age):
            raise ValueError(f"Invalid age: {age}")

        self.id = User._next_id
        User._next_id += 1
        self.name = name
        self.email = email
        self.age = age
        User._users.append(self)

    def update(self, name=None, email=None, age=None):
        if name is not None:
            self.name = name
        if email is not None:
            if not User.validate_email(email):
                raise ValueError(f"Invalid email: {email}")
            self.email = email
        if age is not None:
            if not User.validate_age(age):
                raise ValueError(f"Invalid age: {age}")
            self.age = age
        return self

    def delete(self):
        User._users = [u for u in User._users if u.id != self.id]

    @classmethod
    def get(cls, user_id):
        for user in cls._users:
            if user.id == user_id:
                return user
        return None

    @classmethod
    def all(cls):
        return cls._users.copy()

    @staticmethod
    def validate_email(email):
        return '@' in email and '.' in email.split('@')[1]

    @staticmethod
    def validate_age(age):
        return isinstance(age, int) and 0 < age < 150

    def __repr__(self):
        return f"User(id={self.id}, name={self.name!r}, email={self.email!r}, age={self.age})"
```

### Key improvements over the procedural version

| Aspect | Procedural | OOP |
|--------|-----------|-----|
| **State** | Global `users` list | Encapsulated in `User._users` |
| **Identity** | Plain dictionary | Object with typed attributes |
| **ID generation** | `len(users) + 1` (buggy after deletions) | Monotonic counter `_next_id` |
| **Validation** | Orphaned functions | Static methods invoked in lifecycle |
| **Update** | `if name:` skips empty strings | `is not None` checks (explicit semantics) |

### Usage comparison

```python
# Procedural
user_dict = create_user("Alice", "alice@example.com", 30)
update_user(user_dict['id'], age=31)
delete_user(user_dict['id'])

# OOP
alice = User("Alice", "alice@example.com", 30)
alice.update(age=31)
alice.delete()

# Finding a user
bob = User.get(1)
if bob:
    bob.update(name="Robert")
```

